#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 100005
#define MAX_M 100005
int N, K, M;
int bishopX[MAX_K], bishopY[MAX_K];
int otherX[MAX_M], otherY[MAX_M];
int safeCells;
int visited[MAX_N][MAX_N];
void bfs(int x, int y) {
    int dx[] = {-1, -1, 1, 1};
    int dy[] = {-1, 1, -1, 1};
    for (int i = 0; i < 4; i++) {
        int nx = x + dx[i];
        int ny = y + dy[i];
        while (nx >= 1 && nx <= N && ny >= 1 && ny <= N && !visited[nx][ny]) {
            if (nx == otherX[i] && ny == otherY[i]) break;
            visited[nx][ny] = 1;
            safeCells++;
            nx += dx[i];
            ny += dy[i];
        }
    }
}
int main() {
    scanf("%d %d %d", &N, &K, &M);
    for (int i = 0; i < K; i++) {
        scanf("%d %d", &bishopX[i], &bishopY[i]);
    }
    for (int i = 0; i < M; i++) {
        scanf("%d %d", &otherX[i], &otherY[i]);
    }
    for (int i = 0; i < K; i++) {
        bfs(bishopX[i], bishopY[i]);
    }
    printf("%d\n", safeCells);
    return 0;
}

