#include <iostream>
#include <vector>
using namespace std;
#define MAX_N 100005
#define MAX_M 100005
int N, K, M;
vector<pair<int, int>> bishops;
vector<pair<int, int>> others;
int safeCells;
bool visited[MAX_N][MAX_N];
void bfs(int x, int y) {
    int dx[] = {-1, -1, 1, 1};
    int dy[] = {-1, 1, -1, 1};
    for (int i = 0; i < 4; i++) {
        int nx = x + dx[i];
        int ny = y + dy[i];
        while (nx >= 1 && nx <= N && ny >= 1 && ny <= N && !visited[nx][ny]) {
            bool found = false;
            for (auto &other : others) {
                if (nx == other.first && ny == other.second) {
                    found = true;
                    break;
                }
            }
            if (found) break;
            visited[nx][ny] = true;
            safeCells++;
            nx += dx[i];
            ny += dy[i];
        }
    }
}
int main() {
    cin >> N >> K >> M;
    for (int i = 0; i < K; i++) {
        int x, y;
        cin >> x >> y;
        bishops.push_back({x, y});
    }
    for (int i = 0; i < M; i++) {
        int x, y;
        cin >> x >> y;
        others.push_back({x, y});
    }
    for (auto &bishop : bishops) {
        bfs(bishop.first, bishop.second);
    }
    cout << safeCells << endl;
    return 0;
}

