import java.util.Scanner;
public class Main {
    static final int MAX_N = 100005;
    static final int MAX_M = 100005;
    static int N, K, M;
    static int[] bishopX = new int[MAX_N];
    static int[] bishopY = new int[MAX_N];
    static int[] otherX = new int[MAX_M];
    static int[] otherY = new int[MAX_M];
    static int safeCells;
    static boolean[][] visited = new boolean[MAX_N][MAX_N];
    public static void bfs(int x, int y) {
        int dx[] = {-1, -1, 1, 1};
        int dy[] = {-1, 1, -1, 1};
        for (int i = 0; i < 4; i++) {
            int nx = x + dx[i];
            int ny = y + dy[i];
            while (nx >= 1 && nx <= N && ny >= 1 && ny <= N && !visited[nx][ny]) {
                boolean found = false;
                for (int j = 0; j < M; j++) {
                    if (nx == otherX[j] && ny == otherY[j]) {
                        found = true;
                        break;
                    }
                }
                if (found) break;
                visited[nx][ny] = true;
                safeCells++;
                nx += dx[i];
                ny += dy[i];
            }
        }
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        N = sc.nextInt();
        K = sc.nextInt();
        M = sc.nextInt();
        for (int i = 0; i < K; i++) {
            bishopX[i] = sc.nextInt();
            bishopY[i] = sc.nextInt();
        }
        for (int i = 0; i < M; i++) {
            otherX[i] = sc.nextInt();
            otherY[i] = sc.nextInt();
        }
        for (int i = 0; i < K; i++) {
            bfs(bishopX[i], bishopY[i]);
        }
        System.out.println(safeCells);
    }
}

