const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
function nextLine() {
    return lines[idx++];
}
let [N, K, M] = nextLine().split(' ').map(Number);
let bishops = [];
let others = [];
for (let i = 0; i < K; i++) {
    let [x, y] = nextLine().split(' ').map(Number);
    bishops.push([x, y]);
}
for (let i = 0; i < M; i++) {
    let [x, y] = nextLine().split(' ').map(Number);
    others.push([x, y]);
}
let safeCells = 0;
let visited = Array(N + 1).fill(0).map(() => Array(N + 1).fill(false));
function bfs(x, y) {
    let dx = [-1, -1, 1, 1];
    let dy = [-1, 1, -1, 1];
    for (let i = 0; i < 4; i++) {
        let nx = x + dx[i];
        let ny = y + dy[i];
        while (nx >= 1 && nx <= N && ny >= 1 && ny <= N && !visited[nx][ny]) {
            if (others.some(other => other[0] === nx && other[1] === ny)) {
                break;
            }
            visited[nx][ny] = true;
            safeCells++;
            nx += dx[i];
            ny += dy[i];
        }
    }
}
for (let [x, y] of bishops) {
    bfs(x, y);
}
